/* eslint-disable import/no-extraneous-dependencies */
/* eslint-disable @typescript-eslint/no-unused-vars */
import { LitElement, html, css } from 'lit';
import { property } from 'lit/decorators.js';
import { ScopedElementsMixin } from '@open-wc/scoped-elements/lit-element.js';

/** An editor [[`plugin`]] for creating bay templates using single line diagrams */
export default class BayTemplatePlugin extends ScopedElementsMixin(LitElement) {
  static scopedElements = {
    // Scoped elements will be registered here
  };

  /** The document being edited as provided to plugins by [[`OpenSCD`]]. */
  @property({ attribute: false })
  doc!: XMLDocument;

  /** SCL change indicator */
  @property({ type: Number })
  editCount = 0;

  render() {
    return html`<h1>Bay Template Editor</h1>`;
  }

  static styles = css`
    :host {
      display: block;
      padding: 20px;
      font-family: var(--oscd-theme-text-font, 'Roboto'), sans-serif;
    }

    h1 {
      color: var(--oscd-theme-primary, #2aa198);
      font-size: 2rem;
      font-weight: 300;
      margin: 0;
    }
  `;
}
